const storageKey = "notepad-content";

let beforeUnloadHandler = null;

export function loadContent() {
    return localStorage.getItem(storageKey) || "";
}

export function saveContent(content) {
    localStorage.setItem(storageKey, content);
}

export function clearContent() {
    localStorage.removeItem(storageKey);
}

export function enableUnloadPrompt() {
    if (!beforeUnloadHandler) {
        beforeUnloadHandler = (e) => {
            e.preventDefault();
        };
        window.addEventListener("beforeunload", beforeUnloadHandler);
    }
}

export function disableUnloadPrompt() {
    if (beforeUnloadHandler) {
        window.removeEventListener("beforeunload", beforeUnloadHandler);
        beforeUnloadHandler = null;
    }
}

@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<script type="module" src="@Assets["Components/Pages/Notepad.razor.js"]"></script>

<h1>Notepad</h1>

<textarea class="form-control mb-3" rows="12" @bind="content" @bind:event="oninput"></textarea>

<div class="d-flex align-items-center gap-3 mb-3">
    <button class="btn btn-primary" @onclick="SaveNow">Save now</button>
    <button class="btn btn-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = "";
    private string savedContent = "";
    private DateTime? lastSavedAt;
    private IJSObjectReference? module;
    private Timer? autoSaveTimer;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import",
                $"./{Assets["Components/Pages/Notepad.razor.js"]}");

            content = await module.InvokeAsync<string>("loadContent");
            savedContent = content;

            if (!string.IsNullOrEmpty(content))
            {
                lastSavedAt = DateTime.Now;
            }

            autoSaveTimer = new Timer(AutoSaveCallback, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
            StateHasChanged();
        }
    }

    private async void AutoSaveCallback(object? state)
    {
        await InvokeAsync(async () =>
        {
            await Save();
            StateHasChanged();
        });
    }

    private async Task SaveNow()
    {
        await Save();
    }

    private async Task Save()
    {
        if (module is null) return;

        await module.InvokeVoidAsync("saveContent", content);
        savedContent = content;
        lastSavedAt = DateTime.Now;
        await module.InvokeVoidAsync("disableUnloadPrompt");
    }

    private async Task Clear()
    {
        if (module is null) return;

        content = "";
        savedContent = "";
        lastSavedAt = null;
        await module.InvokeVoidAsync("clearContent");
        await module.InvokeVoidAsync("disableUnloadPrompt");
    }

    private bool HasUnsavedChanges => content != savedContent;

    protected override async Task OnAfterRenderAsync(bool firstRender, bool _)
        => await Task.CompletedTask;

    // Use a property-change approach: after every render, sync the beforeunload state
    protected override async Task OnParametersSetAsync()
    {
        await Task.CompletedTask;
    }

    async ValueTask IAsyncDisposable.DisposeAsync()
    {
        if (autoSaveTimer is not null)
        {
            await autoSaveTimer.DisposeAsync();
        }

        if (module is not null)
        {
            try
            {
                await module.InvokeVoidAsync("disableUnloadPrompt");
                await module.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
    }
}

